def get_encoding_from_headers(headers):
    """Returns encodings from given HTTP Header Dict.

    :param headers: dictionary to extract encoding from.
    """

    content_type = headers.get('content-type')

    if not content_type:
        return None

    content_type, params = cgi.parse_header(content_type)

    if 'charset' in params:
        return params['charset'].strip("'\"")

    if 'text' in content_type:
        return 'ISO-8859-1'

def apparent_encoding(self):
    """The apparent encoding, provided by the chardet library"""
    return chardet.detect(self.content)['encoding']

def json(self, **kwargs):
    """Returns the json-encoded content of a response, if any.

    :param \*\*kwargs: Optional arguments that ``json.loads`` takes.
    """

    if not self.encoding and self.content and len(self.content) > 3:
        # No encoding set. JSON RFC 4627 section 3 states we should expect
        # UTF-8, -16 or -32. Detect which one to use; If the detection or
        # decoding fails, fall back to `self.text` (using chardet to make
        # a best guess).
        encoding = guess_json_utf(self.content)
        if encoding is not None:
            try:
                return complexjson.loads(
                    self.content.decode(encoding), **kwargs
                )
            except UnicodeDecodeError:
                # Wrong UTF codec detected; usually because it's not UTF-8
                # but some other 8-bit codec.  This is an RFC violation,
                # and the server didn't bother to tell us what codec *was*
                # used.
                pass
    return complexjson.loads(self.text, **kwargs)

def raise_for_status(self):
    """Raises stored :class:`HTTPError`, if one occurred."""

    http_error_msg = ''

    if 400 <= self.status_code < 500:
        http_error_msg = '%s Client Error: %s for url: %s' % (self.status_code, self.reason, self.url)

    elif 500 <= self.status_code < 600:
        http_error_msg = '%s Server Error: %s for url: %s' % (self.status_code, self.reason, self.url)

    if http_error_msg:
        raise HTTPError(http_error_msg, response=self)

def close(self):
    """Releases the connection back to the pool. Once this method has been
    called the underlying ``raw`` object must not be accessed again.

    *Note: Should not normally need to be called explicitly.*
    """
    if not self._content_consumed:
        return self.raw.close()

    return self.raw.release_conn()

def generate():
    while 1:
        chunk = self.raw.read(chunk_size)
        if not chunk:
            break
        yield chunk
    self._content_consumed = True

def dispatch_hook(key, hooks, hook_data):
    """Dispatches a hook dictionary on a given piece of data."""

    hooks = hooks or dict()

    if key in hooks:
        hooks = hooks.get(key)

        if hasattr(hooks, '__call__'):
            hooks = [hooks]

        for hook in hooks:
            _hook_data = hook(hook_data)
            if _hook_data is not None:
                hook_data = _hook_data


    return hook_data

def register_hook(self, event, hook):
    """Properly register a hook."""

    self.hooks[event].append(hook)

def deregister_hook(self, event, hook):
    """Deregister a previously registered hook.
    Returns True if the hook existed, False if not.
    """

    try:
        self.hooks[event].remove(hook)
        return True
    except ValueError:
        return False

def _dataset_concat(
    datasets,
    dim,
    data_vars,
    coords,
    compat,
    positions,
    fill_value=dtypes.NA,
    join="outer",
):
    """
    Concatenate a sequence of datasets along a new or existing dimension
    """
    from .dataset import Dataset

    dim, coord = _calc_concat_dim_coord(dim)
    # Make sure we're working on a copy (we'll be loading variables)
    datasets = [ds.copy() for ds in datasets]
    datasets = align(
        *datasets, join=join, copy=False, exclude=[dim], fill_value=fill_value
    )

    dim_coords, dims_sizes, coord_names, data_names = _parse_datasets(datasets)
    dim_names = set(dim_coords)
    unlabeled_dims = dim_names - coord_names

    both_data_and_coords = coord_names & data_names
    if both_data_and_coords:
        raise ValueError(
            "%r is a coordinate in some datasets but not others." % both_data_and_coords
        )
    # we don't want the concat dimension in the result dataset yet
    dim_coords.pop(dim, None)
    dims_sizes.pop(dim, None)

    # case where concat dimension is a coordinate or data_var but not a dimension
    if (dim in coord_names or dim in data_names) and dim not in dim_names:
        datasets = [ds.expand_dims(dim) for ds in datasets]

    # determine which variables to concatentate
    concat_over, equals, concat_dim_lengths = _calc_concat_over(
        datasets, dim, dim_names, data_vars, coords, compat
    )

    # determine which variables to merge, and then merge them according to compat
    variables_to_merge = (coord_names | data_names) - concat_over - dim_names

    result_vars = {}
    if variables_to_merge:
        to_merge = {var: [] for var in variables_to_merge}

        for ds in datasets:
            absent_merge_vars = variables_to_merge - set(ds.variables)
            if absent_merge_vars:
                raise ValueError(
                    "variables %r are present in some datasets but not others. "
                    % absent_merge_vars
                )

            for var in variables_to_merge:
                to_merge[var].append(ds.variables[var])

        for var in variables_to_merge:
            result_vars[var] = unique_variable(
                var, to_merge[var], compat=compat, equals=equals.get(var, None)
            )
    else:
        result_vars = {}
    result_vars.update(dim_coords)

    # assign attrs and encoding from first dataset
    result_attrs = datasets[0].attrs
    result_encoding = datasets[0].encoding

    # check that global attributes are fixed across all datasets if necessary
    for ds in datasets[1:]:
        if compat == "identical" and not utils.dict_equiv(ds.attrs, result_attrs):
            raise ValueError("Dataset global attributes not equal.")

    # we've already verified everything is consistent; now, calculate
    # shared dimension sizes so we can expand the necessary variables
    def ensure_common_dims(vars):
        # ensure each variable with the given name shares the same
        # dimensions and the same shape for all of them except along the
        # concat dimension
        common_dims = tuple(pd.unique([d for v in vars for d in v.dims]))
        if dim not in common_dims:
            common_dims = (dim,) + common_dims
        for var, dim_len in zip(vars, concat_dim_lengths):
            if var.dims != common_dims:
                common_shape = tuple(dims_sizes.get(d, dim_len) for d in common_dims)
                var = var.set_dims(common_dims, common_shape)
            yield var

    # stack up each variable to fill-out the dataset (in order)
    # n.b. this loop preserves variable order, needed for groupby.
    for k in datasets[0].variables:
        if k in concat_over:
            try:
                vars = ensure_common_dims([ds.variables[k] for ds in datasets])
            except KeyError:
                raise ValueError("%r is not present in all datasets." % k)
            combined = concat_vars(vars, dim, positions)
            assert isinstance(combined, Variable)
            result_vars[k] = combined

    result = Dataset(result_vars, attrs=result_attrs)
    absent_coord_names = coord_names - set(result.variables)
    if absent_coord_names:
        raise ValueError(
            "Variables %r are coordinates in some datasets but not others."
            % absent_coord_names
        )
    result = result.set_coords(coord_names)
    result.encoding = result_encoding

    result = result.drop(unlabeled_dims, errors="ignore")

    if coord is not None:
        # add concat dimension last to ensure that its in the final Dataset
        result[coord.name] = coord

    return result

def _calc_concat_over(datasets, dim, dim_names, data_vars, coords, compat):
    """
    Determine which dataset variables need to be concatenated in the result,
    """
    # Return values
    concat_over = set()
    equals = {}

    if dim in dim_names:
        concat_over_existing_dim = True
        concat_over.add(dim)
    else:
        concat_over_existing_dim = False

    concat_dim_lengths = []
    for ds in datasets:
        if concat_over_existing_dim:
            if dim not in ds.dims:
                if dim in ds:
                    ds = ds.set_coords(dim)
        concat_over.update(k for k, v in ds.variables.items() if dim in v.dims)
        concat_dim_lengths.append(ds.dims.get(dim, 1))

    def process_subset_opt(opt, subset):
        if isinstance(opt, str):
            if opt == "different":
                if compat == "override":
                    raise ValueError(
                        "Cannot specify both %s='different' and compat='override'."
                        % subset
                    )
                # all nonindexes that are not the same in each dataset
                for k in getattr(datasets[0], subset):
                    if k not in concat_over:
                        # Compare the variable of all datasets vs. the one
                        # of the first dataset. Perform the minimum amount of
                        # loads in order to avoid multiple loads from disk
                        # while keeping the RAM footprint low.
                        v_lhs = datasets[0].variables[k].load()
                        # We'll need to know later on if variables are equal.
                        computed = []
                        for ds_rhs in datasets[1:]:
                            v_rhs = ds_rhs.variables[k].compute()
                            computed.append(v_rhs)
                            if not getattr(v_lhs, compat)(v_rhs):
                                concat_over.add(k)
                                equals[k] = False
                                # computed variables are not to be re-computed
                                # again in the future
                                for ds, v in zip(datasets[1:], computed):
                                    ds.variables[k].data = v.data
                                break
                        else:
                            equals[k] = True

            elif opt == "all":
                concat_over.update(
                    set(getattr(datasets[0], subset)) - set(datasets[0].dims)
                )
            elif opt == "minimal":
                pass
            else:
                raise ValueError("unexpected value for %s: %s" % (subset, opt))
        else:
            invalid_vars = [k for k in opt if k not in getattr(datasets[0], subset)]
            if invalid_vars:
                if subset == "coords":
                    raise ValueError(
                        "some variables in coords are not coordinates on "
                        "the first dataset: %s" % (invalid_vars,)
                    )
                else:
                    raise ValueError(
                        "some variables in data_vars are not data variables "
                        "on the first dataset: %s" % (invalid_vars,)
                    )
            concat_over.update(opt)

    process_subset_opt(data_vars, "data_vars")
    process_subset_opt(coords, "coords")
    return concat_over, equals, concat_dim_lengths

def process_subset_opt(opt, subset):
    if isinstance(opt, str):
        if opt == "different":
            if compat == "override":
                raise ValueError(
                    "Cannot specify both %s='different' and compat='override'."
                    % subset
                )
            # all nonindexes that are not the same in each dataset
            for k in getattr(datasets[0], subset):
                if k not in concat_over:
                    # Compare the variable of all datasets vs. the one
                    # of the first dataset. Perform the minimum amount of
                    # loads in order to avoid multiple loads from disk
                    # while keeping the RAM footprint low.
                    v_lhs = datasets[0].variables[k].load()
                    # We'll need to know later on if variables are equal.
                    computed = []
                    for ds_rhs in datasets[1:]:
                        v_rhs = ds_rhs.variables[k].compute()
                        computed.append(v_rhs)
                        if not getattr(v_lhs, compat)(v_rhs):
                            concat_over.add(k)
                            equals[k] = False
                            # computed variables are not to be re-computed
                            # again in the future
                            for ds, v in zip(datasets[1:], computed):
                                ds.variables[k].data = v.data
                            break
                    else:
                        equals[k] = True

        elif opt == "all":
            concat_over.update(
                set(getattr(datasets[0], subset)) - set(datasets[0].dims)
            )
        elif opt == "minimal":
            pass
        else:
            raise ValueError("unexpected value for %s: %s" % (subset, opt))
    else:
        invalid_vars = [k for k in opt if k not in getattr(datasets[0], subset)]
        if invalid_vars:
            if subset == "coords":
                raise ValueError(
                    "some variables in coords are not coordinates on "
                    "the first dataset: %s" % (invalid_vars,)
                )
            else:
                raise ValueError(
                    "some variables in data_vars are not data variables "
                    "on the first dataset: %s" % (invalid_vars,)
                )
        concat_over.update(opt)

def ensure_common_dims(vars):
    # ensure each variable with the given name shares the same
    # dimensions and the same shape for all of them except along the
    # concat dimension
    common_dims = tuple(pd.unique([d for v in vars for d in v.dims]))
    if dim not in common_dims:
        common_dims = (dim,) + common_dims
    for var, dim_len in zip(vars, concat_dim_lengths):
        if var.dims != common_dims:
            common_shape = tuple(dims_sizes.get(d, dim_len) for d in common_dims)
            var = var.set_dims(common_dims, common_shape)
        yield var

def dataset_merge_method(
    dataset: "Dataset",
    other: "CoercibleMapping",
    overwrite_vars: Union[Hashable, Iterable[Hashable]],
    compat: str,
    join: str,
    fill_value: Any,
) -> _MergeResult:
    """Guts of the Dataset.merge method.
    """
    # we are locked into supporting overwrite_vars for the Dataset.merge
    # method due for backwards compatibility
    # TODO: consider deprecating it?

    if isinstance(overwrite_vars, Iterable) and not isinstance(overwrite_vars, str):
        overwrite_vars = set(overwrite_vars)
    else:
        overwrite_vars = {overwrite_vars}

    if not overwrite_vars:
        objs = [dataset, other]
        priority_arg = None
    elif overwrite_vars == set(other):
        objs = [dataset, other]
        priority_arg = 1
    else:
        other_overwrite: Dict[Hashable, CoercibleValue] = {}
        other_no_overwrite: Dict[Hashable, CoercibleValue] = {}
        for k, v in other.items():
            if k in overwrite_vars:
                other_overwrite[k] = v
            else:
                other_no_overwrite[k] = v
        objs = [dataset, other_no_overwrite, other_overwrite]
        priority_arg = 2

    return merge_core(
        objs, compat, join, priority_arg=priority_arg, fill_value=fill_value
    )

def dataset_repr(ds):
    summary = ["<xarray.{}>".format(type(ds).__name__)]

    col_width = _calculate_col_width(_get_col_items(ds.variables))

    dims_start = pretty_print("Dimensions:", col_width)
    summary.append("{}({})".format(dims_start, dim_summary(ds)))

    if ds.coords:
        summary.append(coords_repr(ds.coords, col_width=col_width))

    unindexed_dims_str = unindexed_dims_repr(ds.dims, ds.coords)
    if unindexed_dims_str:
        summary.append(unindexed_dims_str)

    summary.append(data_vars_repr(ds.data_vars, col_width=col_width))

    if ds.attrs:
        summary.append(attrs_repr(ds.attrs))

    return "\n".join(summary)

def coords_repr(coords, col_width=None):
    if col_width is None:
        col_width = _calculate_col_width(_get_col_items(coords))
    return _mapping_repr(
        coords, title="Coordinates", summarizer=summarize_coord, col_width=col_width
    )

def summarize_coord(name: Hashable, var, col_width: int):
    is_index = name in var.dims
    marker = "*" if is_index else " "
    if is_index:
        coord = var.variable.to_index_variable()
        if coord.level_names is not None:
            return "\n".join(
                [
                    _summarize_coord_multiindex(coord, col_width, marker),
                    _summarize_coord_levels(coord, col_width),
                ]
            )
    return summarize_variable(name, var.variable, col_width, marker)

def summarize_variable(
    name: Hashable, var, col_width: int, marker: str = " ", max_width: int = None
):
    """Summarize a variable in one line, e.g., for the Dataset.__repr__."""
    if max_width is None:
        max_width_options = OPTIONS["display_width"]
        if not isinstance(max_width_options, int):
            raise TypeError(f"`max_width` value of `{max_width}` is not a valid int")
        else:
            max_width = max_width_options
    first_col = pretty_print(f"  {marker} {name} ", col_width)
    if var.dims:
        dims_str = "({}) ".format(", ".join(map(str, var.dims)))
    else:
        dims_str = ""
    front_str = f"{first_col}{dims_str}{var.dtype} "

    values_width = max_width - len(front_str)
    values_str = inline_variable_array_repr(var, values_width)

    return front_str + values_str

def inline_variable_array_repr(var, max_width):
    """Build a one-line summary of a variable's data."""
    if var._in_memory:
        return format_array_flat(var, max_width)
    elif isinstance(var._data, dask_array_type):
        return inline_dask_repr(var.data)
    elif isinstance(var._data, sparse_array_type):
        return inline_sparse_repr(var.data)
    elif hasattr(var._data, "__array_function__"):
        return maybe_truncate(repr(var._data).replace("\n", " "), max_width)
    else:
        # internal xarray array type
        return "..."

def dim_summary(obj):
    elements = [f"{k}: {v}" for k, v in obj.sizes.items()]
    return ", ".join(elements)

def coords(self) -> DatasetCoordinates:
    """Dictionary of xarray.DataArray objects corresponding to coordinate
    variables
    """
    return DatasetCoordinates(self)

def merge_collected(
    grouped: Dict[Hashable, List[MergeElement]],
    prioritized: Mapping[Hashable, MergeElement] = None,
    compat: str = "minimal",
) -> Tuple[Dict[Hashable, Variable], Dict[Hashable, pd.Index]]:
    """Merge dicts of variables, while resolving conflicts appropriately.

    Parameters
    ----------
    grouped : mapping
    prioritized : mapping
    compat : str
        Type of equality check to use when checking for conflicts.

    Returns
    -------
    Dict with keys taken by the union of keys on list_of_mappings,
    and Variable values corresponding to those that should be found on the
    merged result.
    """
    if prioritized is None:
        prioritized = {}

    _assert_compat_valid(compat)

    merged_vars: Dict[Hashable, Variable] = {}
    merged_indexes: Dict[Hashable, pd.Index] = {}

    for name, elements_list in grouped.items():
        if name in prioritized:
            variable, index = prioritized[name]
            merged_vars[name] = variable
            if index is not None:
                merged_indexes[name] = index
        else:
            indexed_elements = [
                (variable, index)
                for variable, index in elements_list
                if index is not None
            ]

            if indexed_elements:
                # TODO(shoyer): consider adjusting this logic. Are we really
                # OK throwing away variable without an index in favor of
                # indexed variables, without even checking if values match?
                variable, index = indexed_elements[0]
                for _, other_index in indexed_elements[1:]:
                    if not index.equals(other_index):
                        raise MergeError(
                            "conflicting values for index %r on objects to be "
                            "combined:\nfirst value: %r\nsecond value: %r"
                            % (name, index, other_index)
                        )
                if compat == "identical":
                    for other_variable, _ in indexed_elements[1:]:
                        if not dict_equiv(variable.attrs, other_variable.attrs):
                            raise MergeError(
                                "conflicting attribute values on combined "
                                "variable %r:\nfirst value: %r\nsecond value: %r"
                                % (name, variable.attrs, other_variable.attrs)
                            )
                merged_vars[name] = variable
                merged_indexes[name] = index
            else:
                variables = [variable for variable, _ in elements_list]
                try:
                    merged_vars[name] = unique_variable(name, variables, compat)
                except MergeError:
                    if compat != "minimal":
                        # we need more than "minimal" compatibility (for which
                        # we drop conflicting coordinates)
                        raise

    return merged_vars, merged_indexes

def _replace(
    self,
    variables: Dict[Hashable, Variable] = None,
    coord_names: Set[Hashable] = None,
    dims: Dict[Any, int] = None,
    attrs: Union[Dict[Hashable, Any], None, Default] = _default,
    indexes: Union[Dict[Any, pd.Index], None, Default] = _default,
    encoding: Union[dict, None, Default] = _default,
    inplace: bool = False,
) -> "Dataset":
    """Fastpath constructor for internal use.

    Returns an object with optionally with replaced attributes.

    Explicitly passed arguments are *not* copied when placed on the new
    dataset. It is up to the caller to ensure that they have the right type
    and are not used elsewhere.
    """
    if inplace:
        if variables is not None:
            self._variables = variables
        if coord_names is not None:
            self._coord_names = coord_names
        if dims is not None:
            self._dims = dims
        if attrs is not _default:
            self._attrs = attrs
        if indexes is not _default:
            self._indexes = indexes
        if encoding is not _default:
            self._encoding = encoding
        obj = self
    else:
        if variables is None:
            variables = self._variables.copy()
        if coord_names is None:
            coord_names = self._coord_names.copy()
        if dims is None:
            dims = self._dims.copy()
        if attrs is _default:
            attrs = copy.copy(self._attrs)
        if indexes is _default:
            indexes = copy.copy(self._indexes)
        if encoding is _default:
            encoding = copy.copy(self._encoding)
        obj = self._construct_direct(
            variables, coord_names, dims, attrs, indexes, encoding
        )
    return obj

def _overwrite_indexes(self, indexes: Mapping[Any, pd.Index]) -> "Dataset":
    if not indexes:
        return self

    variables = self._variables.copy()
    new_indexes = dict(self.indexes)
    for name, idx in indexes.items():
        variables[name] = IndexVariable(name, idx)
        new_indexes[name] = idx
    obj = self._replace(variables, indexes=new_indexes)

    # switch from dimension to level names, if necessary
    dim_names: Dict[Hashable, str] = {}
    for dim, idx in indexes.items():
        if not isinstance(idx, pd.MultiIndex) and idx.name != dim:
            dim_names[dim] = idx.name
    if dim_names:
        obj = obj.rename(dim_names)
    return obj

def _validate_indexers(
    self, indexers: Mapping[Hashable, Any], missing_dims: str = "raise"
) -> Iterator[Tuple[Hashable, Union[int, slice, np.ndarray, Variable]]]:
    """Here we make sure
    + indexer has a valid keys
    + indexer is in a valid data type
    + string indexers are cast to the appropriate date type if the
      associated index is a DatetimeIndex or CFTimeIndex
    """
    from .dataarray import DataArray

    indexers = drop_dims_from_indexers(indexers, self.dims, missing_dims)

    # all indexers should be int, slice, np.ndarrays, or Variable
    for k, v in indexers.items():
        if isinstance(v, (int, slice, Variable)):
            yield k, v
        elif isinstance(v, DataArray):
            yield k, v.variable
        elif isinstance(v, tuple):
            yield k, as_variable(v)
        elif isinstance(v, Dataset):
            raise TypeError("cannot use a Dataset as an indexer")
        elif isinstance(v, Sequence) and len(v) == 0:
            yield k, np.empty((0,), dtype="int64")
        else:
            v = np.asarray(v)

            if v.dtype.kind in "US":
                index = self.indexes[k]
                if isinstance(index, pd.DatetimeIndex):
                    v = v.astype("datetime64[ns]")
                elif isinstance(index, xr.CFTimeIndex):
                    v = _parse_array_of_cftime_strings(v, index.date_type)

            if v.ndim > 1:
                raise IndexError(
                    "Unlabeled multi-dimensional array cannot be "
                    "used for indexing: {}".format(k)
                )
            yield k, v

def dataset_repr(ds):
    summary = ["<xarray.{}>".format(type(ds).__name__)]

    col_width = _calculate_col_width(_get_col_items(ds.variables))

    dims_start = pretty_print("Dimensions:", col_width)
    summary.append("{}({})".format(dims_start, dim_summary(ds)))

    if ds.coords:
        summary.append(coords_repr(ds.coords, col_width=col_width))

    unindexed_dims_str = unindexed_dims_repr(ds.dims, ds.coords)
    if unindexed_dims_str:
        summary.append(unindexed_dims_str)

    summary.append(data_vars_repr(ds.data_vars, col_width=col_width))

    if ds.attrs:
        summary.append(attrs_repr(ds.attrs))

    return "\n".join(summary)

def __repr__(self):
    return "{}, grouped over {!r} \n{!r} groups with labels {}.".format(
        self.__class__.__name__,
        self._unique_coord.name,
        self._unique_coord.size,
        ", ".join(format_array_flat(self._unique_coord, 30).split()),
    )

def _get_index_and_items(self, index, grouper):
    from .resample_cftime import CFTimeGrouper

    s = pd.Series(np.arange(index.size), index)
    if isinstance(grouper, CFTimeGrouper):
        first_items = grouper.first_items(index)
    else:
        first_items = s.groupby(grouper).first()
        _apply_loffset(grouper, first_items)
    full_index = first_items.index
    if first_items.isnull().any():
        first_items = first_items.dropna()
    return full_index, first_items

def _iter_grouped(self):
    """Iterate over each element in this group"""
    for indices in self._group_indices:
        yield self._obj.isel(**{self._group_dim: indices})

def format_option_help(self, formatter=None):
    if formatter is None:
        formatter = self.formatter
    outputlevel = getattr(formatter, "output_level", 0)
    formatter.store_option_strings(self)
    result = [formatter.format_heading("Options")]
    formatter.indent()
    if self.option_list:
        result.append(optparse.OptionContainer.format_option_help(self, formatter))
        result.append("\n")
    for group in self.option_groups:
        if group.level <= outputlevel and (
            group.description or _level_options(group, outputlevel)
        ):
            result.append(group.format_help(formatter))
            result.append("\n")
    formatter.dedent()
    # Drop the last "\n", or the header if no options or option groups:
    return "".join(result[:-1])

def __init__(self, options: list[str], *args: object) -> None:
    self.options = options
    super().__init__(*args)

def run_pylint(argv: Sequence[str] | None = None) -> None:
    """Run pylint.

    argv can be a sequence of strings normally supplied as arguments on the command line
    """
    from pylint.lint import Run as PylintRun

    try:
        PylintRun(argv or sys.argv[1:])
    except KeyboardInterrupt:
        sys.exit(1)

def options_by_section(
    self,
) -> Iterator[
    tuple[str, list[tuple[str, OptionDict, Any]]]
    | tuple[None, dict[str, list[tuple[str, OptionDict, Any]]]]
]:  # pragma: no cover
    """DEPRECATED: Return an iterator on options grouped by section.

    (section, [list of (optname, optdict, optvalue)])
    """
    warnings.warn(
        "options_by_section has been deprecated. It will be removed "
        "in a future release.",
        DeprecationWarning,
    )
    sections: dict[str, list[tuple[str, OptionDict, Any]]] = {}
    for optname, optdict in self.options:
        with warnings.catch_warnings():
            warnings.filterwarnings("ignore", category=DeprecationWarning)
            sections.setdefault(optdict.get("group"), []).append(  # type: ignore[arg-type]
                (optname, optdict, self.option_value(optname))
            )
    if None in sections:
        yield None, sections.pop(None)  # type: ignore[call-overload]
    for section, options in sorted(sections.items()):
        yield section.upper(), options

def options_and_values(
    self, options: Options | None = None
) -> Iterator[tuple[str, OptionDict, Any]]:  # pragma: no cover
    """DEPRECATED."""
    warnings.warn(
