            warnings.filterwarnings("ignore", category=DeprecationWarning)
            yield optname, optdict, self.option_value(optname)

def _parse_toml(self, config_file: Path, parser: configparser.ConfigParser) -> None:
    """Parse and handle errors of a toml configuration file."""
    with open(config_file, mode="rb") as fp:
        content = tomllib.load(fp)
    try:
        sections_values = content["tool"]["pylint"]
    except KeyError:
        return
    for section, values in sections_values.items():
        section_name = section.upper()
        # TOML has rich types, convert values to
        # strings as ConfigParser expects.
        if not isinstance(values, dict):
            # This class is a mixin: add_message comes from the `PyLinter` class
            self.add_message(  # type: ignore[attr-defined]
                "bad-configuration-section", line=0, args=(section, values)
            )
            continue
        for option, value in values.items():
            if isinstance(value, bool):
                values[option] = "yes" if value else "no"
            elif isinstance(value, list):
                values[option] = ",".join(value)
            else:
                values[option] = str(value)
        for option, value in values.items():
            try:
                parser.set(section_name, option, value=value)
            except configparser.NoSectionError:
                parser.add_section(section_name)
                parser.set(section_name, option, value=value)

def load_provider_defaults(self):
    """Initialize configuration using default values."""
    for provider in self.options_providers:
        provider.load_defaults()

def generate_config(
    self, stream: TextIO | None = None, skipsections: tuple[str, ...] = ()
) -> None:
    """Write a configuration file according to the current configuration
    into the given stream or stdout.
    """
    options_by_section: dict[str, list[tuple[str, OptionDict, Any]]] = {}
    sections = []
    for provider in self.options_providers:
        for section, options in provider.options_by_section():
            if section is None:
                section = provider.name
            if section in skipsections:
                continue
            options = [
                (n, d, v)
                for (n, d, v) in options
                if d.get("type") is not None and not d.get("deprecated")
            ]
            if not options:
                continue
            if section not in sections:
                sections.append(section)
            all_options = options_by_section.setdefault(section, [])
            all_options += options
    stream = stream or sys.stdout
    printed = False
    for section in sections:
        if printed:
            print("\n", file=stream)
        utils.format_section(
            stream, section.upper(), sorted(options_by_section[section])
        )
        printed = True

def read_config_file(
    self, config_file: Path | None = None, verbose: bool = False
) -> None:
    """Read the configuration file but do not load it (i.e. dispatching
    values to each option's provider).
    """
    if config_file:
        config_file = Path(os.path.expandvars(config_file)).expanduser()
        if not config_file.exists():
            raise OSError(f"The config file {str(config_file)} doesn't exist!")

        parser = self.cfgfile_parser
        if config_file.suffix == ".toml":
            try:
                self._parse_toml(config_file, parser)
            except tomllib.TOMLDecodeError:
                pass
        else:
            # Use this encoding in order to strip the BOM marker, if any.
            with open(config_file, encoding="utf_8_sig") as fp:
                parser.read_file(fp)
            # normalize each section's title
            for sect, values in list(parser._sections.items()):
                if sect.startswith("pylint."):
                    sect = sect[len("pylint.") :]
                if not sect.isupper() and values:
                    parser._sections[sect.upper()] = values

    if not verbose:
        return
    if config_file and config_file.exists():
        msg = f"Using config file '{config_file}'"
    else:
        msg = "No config file found, using default configuration"
    print(msg, file=sys.stderr)

def load_configuration_from_config(self, config):
    for opt, opt_value in config.items():
        opt = opt.replace("_", "-")
        provider = self._all_options[opt]
        provider.set_option(opt, opt_value)

def _modpath_from_file(filename: str, is_namespace: bool, path: list[str]) -> list[str]:
    def _is_package_cb(inner_path: str, parts: list[str]) -> bool:
        return modutils.check_modpath_has_init(inner_path, parts) or is_namespace

    return modutils.modpath_from_file_with_callback(
        filename, path=path, is_package_cb=_is_package_cb
    )

def get_python_path(filepath: str) -> str:
    """TODO This get the python path with the (bad) assumption that there is always
    an __init__.py.

    This is not true since python 3.3 and is causing problem.
    """
    dirname = os.path.realpath(os.path.expanduser(filepath))
    if not os.path.isdir(dirname):
        dirname = os.path.dirname(dirname)
    while True:
        if not os.path.exists(os.path.join(dirname, "__init__.py")):
            return dirname
        old_dirname = dirname
        dirname = os.path.dirname(dirname)
        if old_dirname == dirname:
            return os.getcwd()

def _is_in_ignore_list_re(element: str, ignore_list_re: list[Pattern[str]]) -> bool:
    """Determines if the element is matched in a regex ignore-list."""
    return any(file_pattern.match(element) for file_pattern in ignore_list_re)

def _is_ignored_file(
    element: str,
    ignore_list: list[str],
    ignore_list_re: list[Pattern[str]],
    ignore_list_paths_re: list[Pattern[str]],
) -> bool:
    element = os.path.normpath(element)
    basename = os.path.basename(element)
    return (
        basename in ignore_list
        or _is_in_ignore_list_re(basename, ignore_list_re)
        or _is_in_ignore_list_re(element, ignore_list_paths_re)
    )

def expand_modules(
    files_or_modules: Sequence[str],
    ignore_list: list[str],
    ignore_list_re: list[Pattern[str]],
    ignore_list_paths_re: list[Pattern[str]],
) -> tuple[list[ModuleDescriptionDict], list[ErrorDescriptionDict]]:
    """Take a list of files/modules/packages and return the list of tuple
    (file, module name) which have to be actually checked.
    """
    result: list[ModuleDescriptionDict] = []
    errors: list[ErrorDescriptionDict] = []
    path = sys.path.copy()

    for something in files_or_modules:
        basename = os.path.basename(something)
        if _is_ignored_file(
            something, ignore_list, ignore_list_re, ignore_list_paths_re
        ):
            continue
        module_path = get_python_path(something)
        additional_search_path = [".", module_path] + path
        if os.path.exists(something):
            # this is a file or a directory
            try:
                modname = ".".join(
                    modutils.modpath_from_file(something, path=additional_search_path)
                )
            except ImportError:
                modname = os.path.splitext(basename)[0]
            if os.path.isdir(something):
                filepath = os.path.join(something, "__init__.py")
            else:
                filepath = something
        else:
            # suppose it's a module or package
            modname = something
            try:
                filepath = modutils.file_from_modpath(
                    modname.split("."), path=additional_search_path
                )
                if filepath is None:
                    continue
            except (ImportError, SyntaxError) as ex:
                # The SyntaxError is a Python bug and should be
                # removed once we move away from imp.find_module: https://bugs.python.org/issue10588
                errors.append({"key": "fatal", "mod": modname, "ex": ex})
                continue
        filepath = os.path.normpath(filepath)
        modparts = (modname or something).split(".")
        try:
            spec = modutils.file_info_from_modpath(
                modparts, path=additional_search_path
            )
        except ImportError:
            # Might not be acceptable, don't crash.
            is_namespace = False
            is_directory = os.path.isdir(something)
        else:
            is_namespace = modutils.is_namespace(spec)
            is_directory = modutils.is_directory(spec)
        if not is_namespace:
            result.append(
                {
                    "path": filepath,
                    "name": modname,
                    "isarg": True,
                    "basepath": filepath,
                    "basename": modname,
                }
            )
        has_init = (
            not (modname.endswith(".__init__") or modname == "__init__")
            and os.path.basename(filepath) == "__init__.py"
        )
        if has_init or is_namespace or is_directory:
            for subfilepath in modutils.get_module_files(
                os.path.dirname(filepath), ignore_list, list_all=is_namespace
            ):
                if filepath == subfilepath:
                    continue
                if _is_in_ignore_list_re(
                    os.path.basename(subfilepath), ignore_list_re
                ) or _is_in_ignore_list_re(subfilepath, ignore_list_paths_re):
                    continue

                modpath = _modpath_from_file(
                    subfilepath, is_namespace, path=additional_search_path
                )
                submodname = ".".join(modpath)
                result.append(
                    {
                        "path": subfilepath,
                        "name": submodname,
                        "isarg": False,
                        "basepath": filepath,
                        "basename": modname,
                    }
                )
    return result, errors

def get_module_and_frameid(node: nodes.NodeNG) -> tuple[str, str]:
    """Return the module name and the frame id in the module."""
    frame = node.frame(future=True)
    module, obj = "", []
    while frame:
        if isinstance(frame, Module):
            module = frame.name
        else:
            obj.append(getattr(frame, "name", "<lambda>"))
        try:
            frame = frame.parent.frame(future=True)
        except AttributeError:
            break
    obj.reverse()
    return module, ".".join(obj)

def _get_ansi_code(msg_style: MessageStyle) -> str:
    """Return ANSI escape code corresponding to color and style.

    :param msg_style: the message style

    :raise KeyError: if a nonexistent color or style identifier is given

    :return: the built escape code
    """
    ansi_code = [ANSI_STYLES[effect] for effect in msg_style.style]
    if msg_style.color:
        if msg_style.color.isdigit():
            ansi_code.extend(["38", "5"])
            ansi_code.append(msg_style.color)
        else:
            ansi_code.append(ANSI_COLORS[msg_style.color])
    if ansi_code:
        return ANSI_PREFIX + ";".join(ansi_code) + ANSI_END
    return ""

