def parse_pragma(pylint_pragma: str) -> Generator[PragmaRepresenter, None, None]:
    action: Optional[str] = None
    messages: List[str] = []
    assignment_required = False
    previous_token = ""

    for mo in re.finditer(TOK_REGEX, pylint_pragma):
        kind = mo.lastgroup
        value = mo.group()

        if kind == "ASSIGN":
            if not assignment_required:
                if action:
                    # A keyword has been found previously but doesn't support assignment
                    raise UnRecognizedOptionError(
                        "The keyword doesn't support assignment", action
                    )
                if previous_token:
                    # Something found previously but not a known keyword
                    raise UnRecognizedOptionError(
                        "The keyword is unknown", previous_token
                    )
                # Nothing at all detected before this assignment
                raise InvalidPragmaError("Missing keyword before assignment", "")
            assignment_required = False
        elif assignment_required:
            raise InvalidPragmaError(
                "The = sign is missing after the keyword", action or ""
            )
        elif kind == "KEYWORD":
            if action:
                yield emit_pragma_representer(action, messages)
            action = value
            messages = []
            assignment_required = action in MESSAGE_KEYWORDS
        elif kind in {"MESSAGE_STRING", "MESSAGE_NUMBER"}:
            messages.append(value)
            assignment_required = False
        else:
            raise RuntimeError("Token not recognized")

        previous_token = value

    if action:
        yield emit_pragma_representer(action, messages)
    else:
        raise UnRecognizedOptionError("The keyword is unknown", previous_token)

def preprocess_options(args, search_for):
    """Look for some options (keys of <search_for>) which have to be processed
    before others

    values of <search_for> are callback functions to call when the option is
    found
    """
    i = 0
    while i < len(args):
        arg = args[i]
        if not arg.startswith("--"):
            i += 1
        else:
            try:
                option, val = arg[2:].split("=", 1)
            except ValueError:
                option, val = arg[2:], None
            try:
                cb, takearg = search_for[option]
            except KeyError:
                i += 1
            else:
                del args[i]
                if takearg and val is None:
                    if i >= len(args) or args[i].startswith("-"):
                        msg = f"Option {option} expects a value"
                        raise ArgumentPreprocessingError(msg)
                    val = args[i]
                    del args[i]
                elif not takearg and val is not None:
                    msg = f"Option {option} doesn't expects a value"
                    raise ArgumentPreprocessingError(msg)
                cb(option, val)

def _non_empty_string_validator(opt, _, value):
    if not value:
        msg = "indent string can't be empty."
        raise optparse.OptionValueError(msg)
    return utils._unquote(value)

def _choice_validator(choices, name, value):
    if value not in choices:
        msg = "option %s: invalid value: %r, should be in %s"
        raise optparse.OptionValueError(msg % (name, value, choices))
    return value

def _non_empty_string_transformer(value: str) -> str:
    """Check that a string is not empty and remove quotes."""
    if not value:
        raise argparse.ArgumentTypeError("Option cannot be an empty string.")
    return pylint_utils._unquote(value)

def _path_transformer(value: str) -> str:
    """Expand user and variables in a path."""
    return os.path.expandvars(os.path.expanduser(value))

def _py_version_transformer(value: str) -> tuple[int, ...]:
    """Transforms a version string into a version tuple."""
    try:
        version = tuple(int(val) for val in value.replace(",", ".").split("."))
    except ValueError:
        raise argparse.ArgumentTypeError(
            f"{value} has an invalid format, should be a version string. E.g., '3.8'"
        ) from None
    return version

def _parse_ini_file(self, file_path: Path) -> tuple[dict[str, str], list[str]]:
    """Parse and handle errors of a ini configuration file."""
    parser = configparser.ConfigParser(inline_comment_prefixes=("#", ";"))

    # Use this encoding in order to strip the BOM marker, if any.
    with open(file_path, encoding="utf_8_sig") as fp:
        parser.read_file(fp)

    config_content: dict[str, str] = {}
    options: list[str] = []
    for section in parser.sections():
        if self._ini_file_with_sections(file_path) and not section.startswith(
            "pylint"
        ):
            if section.lower() == "master":
                # TODO: 3.0: Remove deprecated handling of master, only allow 'pylint.' sections
                warnings.warn(
                    "The use of 'MASTER' or 'master' as configuration section for pylint "
                    "has been deprecated, as it's bad practice to not start sections titles with the "
                    "tool name. Please use 'pylint.main' instead.",
                    UserWarning,
                )
            else:
                continue
        for opt, value in parser[section].items():
            config_content[opt] = value
            options += [f"--{opt}", value]
    return config_content, options

def _ini_file_with_sections(file_path: Path) -> bool:
    """Return whether the file uses sections."""
    if "setup.cfg" in file_path.parts:
        return True
    if "tox.ini" in file_path.parts:
        return True
    return False

def _parse_toml_file(self, file_path: Path) -> tuple[dict[str, str], list[str]]:
    """Parse and handle errors of a toml configuration file."""
    try:
        with open(file_path, mode="rb") as fp:
            content = tomllib.load(fp)
    except tomllib.TOMLDecodeError as e:
        self.linter.add_message("config-parse-error", line=0, args=str(e))
        return {}, []

    try:
        sections_values = content["tool"]["pylint"]
    except KeyError:
        return {}, []

    config_content: dict[str, str] = {}
    options: list[str] = []
    for opt, values in sections_values.items():
        if isinstance(values, dict):
            for config, value in values.items():
                value = _parse_rich_type_value(value)
                config_content[config] = value
                options += [f"--{config}", value]
        else:
            values = _parse_rich_type_value(values)
            config_content[opt] = values
            options += [f"--{opt}", values]
    return config_content, options

def parse_config_file(
    self, file_path: Path | None
) -> tuple[dict[str, str], list[str]]:
    """Parse a config file and return str-str pairs."""
    if file_path is None:
        if self.verbose_mode:
            print(
                "No config file found, using default configuration", file=sys.stderr
            )
        return {}, []

    file_path = Path(os.path.expandvars(file_path)).expanduser()
    if not file_path.exists():
        raise OSError(f"The config file {file_path} doesn't exist!")

    if self.verbose_mode:
        print(f"Using config file {file_path}", file=sys.stderr)

    try:
        if file_path.suffix == ".toml":
            return self._parse_toml_file(file_path)
        return self._parse_ini_file(file_path)
    except (configparser.Error, tomllib.TOMLDecodeError) as e:
        self.linter.add_message("config-parse-error", line=0, args=str(e))
        return {}, []

def _load_default_argument_values(self) -> None:
    """Loads the default values of all registered options."""
    self.config = self._arg_parser.parse_args([], self.config)

def _add_arguments_to_parser(
    self, section: str, section_desc: str | None, argument: _Argument
) -> None:
    """Add an argument to the correct argument section/group."""
    try:
        section_group = self._argument_groups_dict[section]
    except KeyError:
        if section_desc:
            section_group = self._arg_parser.add_argument_group(
                section, section_desc
            )
        else:
            section_group = self._arg_parser.add_argument_group(title=section)
        self._argument_groups_dict[section] = section_group
    self._add_parser_option(section_group, argument)

def run(self, mod: ast.Module) -> None:
    """Find all assert statements in *mod* and rewrite them."""
    if not mod.body:
        # Nothing to do.
        return

    # We'll insert some special imports at the top of the module, but after any
    # docstrings and __future__ imports, so first figure out where that is.
    doc = getattr(mod, "docstring", None)
    expect_docstring = doc is None
    if doc is not None and self.is_rewrite_disabled(doc):
        return
    pos = 0
    item = None
    for item in mod.body:
        if (
            expect_docstring
            and isinstance(item, ast.Expr)
            and isinstance(item.value, ast.Constant)
        ):
            doc = item.value.value
            if self.is_rewrite_disabled(doc):
                return
            expect_docstring = False
        elif (
            isinstance(item, ast.ImportFrom)
            and item.level == 0
            and item.module == "__future__"
        ):
            pass
        else:
            break
        pos += 1
    # Special case: for a decorated function, set the lineno to that of the
    # first decorator, not the `def`. Issue #4984.
    if isinstance(item, ast.FunctionDef) and item.decorator_list:
        lineno = item.decorator_list[0].lineno
    else:
        lineno = item.lineno
    # Now actually insert the special imports.
    if sys.version_info >= (3, 10):
        aliases = [
            ast.alias("builtins", "@py_builtins", lineno=lineno, col_offset=0),
            ast.alias(
                "_pytest.assertion.rewrite",
                "@pytest_ar",
                lineno=lineno,
                col_offset=0,
            ),
        ]
    else:
        aliases = [
            ast.alias("builtins", "@py_builtins"),
            ast.alias("_pytest.assertion.rewrite", "@pytest_ar"),
        ]
    imports = [
        ast.Import([alias], lineno=lineno, col_offset=0) for alias in aliases
    ]
    mod.body[pos:pos] = imports

    # Collect asserts.
    nodes: List[ast.AST] = [mod]
    while nodes:
        node = nodes.pop()
        for name, field in ast.iter_fields(node):
            if isinstance(field, list):
                new: List[ast.AST] = []
                for i, child in enumerate(field):
                    if isinstance(child, ast.Assert):
                        # Transform assert.
                        new.extend(self.visit(child))
                    else:
                        new.append(child)
                        if isinstance(child, ast.AST):
                            nodes.append(child)
                setattr(node, name, new)
            elif (
                isinstance(field, ast.AST)
                # Don't recurse into expressions as they can't contain
                # asserts.
                and not isinstance(field, ast.expr)
            ):
                nodes.append(field)

def _importtestmodule(self):
    # We assume we are only called once per module.
    importmode = self.config.getoption("--import-mode")
    try:
        mod = import_path(self.path, mode=importmode, root=self.config.rootpath)
    except SyntaxError as e:
        raise self.CollectError(
            ExceptionInfo.from_current().getrepr(style="short")
        ) from e
    except ImportPathMismatchError as e:
        raise self.CollectError(
            "import file mismatch:\n"
            "imported module %r has this __file__ attribute:\n"
            "  %s\n"
            "which is not the same as the test file we want to collect:\n"
            "  %s\n"
            "HINT: remove __pycache__ / .pyc files and/or use a "
            "unique basename for your test file modules" % e.args
        ) from e
    except ImportError as e:
        exc_info = ExceptionInfo.from_current()
        if self.config.getoption("verbose") < 2:
            exc_info.traceback = exc_info.traceback.filter(filter_traceback)
        exc_repr = (
            exc_info.getrepr(style="short")
            if exc_info.traceback
            else exc_info.exconly()
        )
        formatted_tb = str(exc_repr)
        raise self.CollectError(
            "ImportError while importing test module '{path}'.\n"
            "Hint: make sure your test modules/packages have valid Python names.\n"
            "Traceback:\n"
            "{traceback}".format(path=self.path, traceback=formatted_tb)
        ) from e
    except skip.Exception as e:
        if e.allow_module_level:
            raise
        raise self.CollectError(
            "Using pytest.skip outside of a test will skip the entire module. "
            "If that's your intention, pass `allow_module_level=True`. "
            "If you want to skip a specific test or an entire class, "
            "use the @pytest.mark.skip or @pytest.mark.skipif decorators."
        ) from e
    self.config.pluginmanager.consider_module(mod)
    return mod

def _inject_setup_module_fixture(self) -> None:
    """Inject a hidden autouse, module scoped fixture into the collected module object
    that invokes setUpModule/tearDownModule if either or both are available.

    Using a fixture to invoke this methods ensures we play nicely and unsurprisingly with
    other fixtures (#517).
    """
    has_nose = self.config.pluginmanager.has_plugin("nose")
    setup_module = _get_first_non_fixture_func(
        self.obj, ("setUpModule", "setup_module")
    )
    if setup_module is None and has_nose:
        # The name "setup" is too common - only treat as fixture if callable.
        setup_module = _get_first_non_fixture_func(self.obj, ("setup",))
        if not callable(setup_module):
            setup_module = None
    teardown_module = _get_first_non_fixture_func(
        self.obj, ("tearDownModule", "teardown_module")
    )
    if teardown_module is None and has_nose:
        teardown_module = _get_first_non_fixture_func(self.obj, ("teardown",))
        # Same as "setup" above - only treat as fixture if callable.
        if not callable(teardown_module):
            teardown_module = None

    if setup_module is None and teardown_module is None:
        return

    @fixtures.fixture(
        autouse=True,
        scope="module",
        # Use a unique name to speed up lookup.
        name=f"_xunit_setup_module_fixture_{self.obj.__name__}",
    )
    def xunit_setup_module_fixture(request) -> Generator[None, None, None]:
        if setup_module is not None:
            _call_with_optional_argument(setup_module, request.module)
        yield
        if teardown_module is not None:
            _call_with_optional_argument(teardown_module, request.module)

    self.obj.__pytest_setup_module = xunit_setup_module_fixture

def _inject_setup_function_fixture(self) -> None:
    """Inject a hidden autouse, function scoped fixture into the collected module object
    that invokes setup_function/teardown_function if either or both are available.

    Using a fixture to invoke this methods ensures we play nicely and unsurprisingly with
    other fixtures (#517).
    """
    setup_function = _get_first_non_fixture_func(self.obj, ("setup_function",))
    teardown_function = _get_first_non_fixture_func(
        self.obj, ("teardown_function",)
    )
    if setup_function is None and teardown_function is None:
        return

    @fixtures.fixture(
        autouse=True,
        scope="function",
        # Use a unique name to speed up lookup.
        name=f"_xunit_setup_function_fixture_{self.obj.__name__}",
    )
    def xunit_setup_function_fixture(request) -> Generator[None, None, None]:
        if request.instance is not None:
            # in this case we are bound to an instance, so we need to let
            # setup_method handle this
            yield
            return
        if setup_function is not None:
            _call_with_optional_argument(setup_function, request.function)
        yield
        if teardown_function is not None:
            _call_with_optional_argument(teardown_function, request.function)

    self.obj.__pytest_setup_function = xunit_setup_function_fixture

def assertrepr_compare(config, op, left, right):
    """Return specialised explanations for some operators/operands"""
    width = 80 - 15 - len(op) - 2  # 15 chars indentation, 1 space around op
    left_repr = saferepr(left, maxsize=int(width // 2))
    right_repr = saferepr(right, maxsize=width - len(left_repr))

    summary = u"%s %s %s" % (ecu(left_repr), op, ecu(right_repr))

    verbose = config.getoption("verbose")
    explanation = None
    try:
        if op == "==":
            if istext(left) and istext(right):
                explanation = _diff_text(left, right, verbose)
            else:
                if issequence(left) and issequence(right):
                    explanation = _compare_eq_sequence(left, right, verbose)
                elif isset(left) and isset(right):
                    explanation = _compare_eq_set(left, right, verbose)
                elif isdict(left) and isdict(right):
                    explanation = _compare_eq_dict(left, right, verbose)
                elif type(left) == type(right) and (isdatacls(left) or isattrs(left)):
                    type_fn = (isdatacls, isattrs)
                    explanation = _compare_eq_cls(left, right, verbose, type_fn)
                elif verbose > 0:
                    explanation = _compare_eq_verbose(left, right)
                if isiterable(left) and isiterable(right):
                    expl = _compare_eq_iterable(left, right, verbose)
                    if explanation is not None:
                        explanation.extend(expl)
                    else:
                        explanation = expl
        elif op == "not in":
            if istext(left) and istext(right):
                explanation = _notin_text(left, right, verbose)
    except outcomes.Exit:
        raise
    except Exception:
        explanation = [
            u"(pytest_assertion plugin: representation of details failed.  "
            u"Probably an object has a faulty __repr__.)",
            six.text_type(_pytest._code.ExceptionInfo.from_current()),
        ]

    if not explanation:
        return None

    return [summary] + explanation

def builtin(self, name):
    """Return the builtin called *name*."""
    builtin_name = ast.Name("@py_builtins", ast.Load())
    return ast.Attribute(builtin_name, name, ast.Load())

def helper(self, name, *args):
    """Call a helper in this module."""
    py_name = ast.Name("@pytest_ar", ast.Load())
    attr = ast.Attribute(py_name, name, ast.Load())
    return ast_Call(attr, list(args), [])

def getfixtureinfo(self, node, func, cls, funcargs=True):
    if funcargs and not getattr(node, "nofuncargs", False):
        argnames = getfuncargnames(func, cls=cls)
    else:
        argnames = ()
    usefixtures = itertools.chain.from_iterable(
        mark.args for mark in node.iter_markers(name="usefixtures")
    )
    initialnames = tuple(usefixtures) + argnames
    fm = node.session._fixturemanager
    initialnames, names_closure, arg2fixturedefs = fm.getfixtureclosure(
        initialnames, node
    )
    return FuncFixtureInfo(argnames, initialnames, names_closure, arg2fixturedefs)

def pytest_report_header(self, config):
    line = "rootdir: %s" % config.rootdir

    if config.inifile:
        line += ", inifile: " + config.rootdir.bestrelpath(config.inifile)

    testpaths = config.getini("testpaths")
    if testpaths and config.args == testpaths:
        rel_paths = [config.rootdir.bestrelpath(x) for x in testpaths]
        line += ", testpaths: {}".format(", ".join(rel_paths))
    result = [line]

    plugininfo = config.pluginmanager.list_plugin_distinfo()
    if plugininfo:
        result.append("plugins: %s" % ", ".join(_plugin_nameversions(plugininfo)))
    return result

def pytest_cmdline_parse(self, pluginmanager, args):
    try:
        self.parse(args)
    except UsageError:

        # Handle --version and --help here in a minimal fashion.
        # This gets done via helpconfig normally, but its
        # pytest_cmdline_main is not called in case of errors.
        if getattr(self.option, "version", False) or "--version" in args:
            from _pytest.helpconfig import showversion

            showversion(self)
        elif (
            getattr(self.option, "help", False) or "--help" in args or "-h" in args
        ):
            self._parser._getparser().print_help()
            sys.stdout.write(
                "\nNOTE: displaying only minimal help due to UsageError.\n\n"
            )

        raise

    return self

def _get_active_fixturedef(self, argname):
    try:
        return self._fixture_defs[argname]
    except KeyError:
        try:
            fixturedef = self._getnextfixturedef(argname)
        except FixtureLookupError:
            if argname == "request":
                cached_result = (self, [0], None)
                scope = "function"
                return PseudoFixtureDef(cached_result, scope)
            raise
    # remove indent to prevent the python3 exception
    # from leaking into the call
    self._compute_fixture_value(fixturedef)
    self._fixture_defs[argname] = fixturedef
    return fixturedef

def __init__(self, terminalwriter, *args, **kwargs):
    super(ColoredLevelFormatter, self).__init__(*args, **kwargs)
    if six.PY2:
        self._original_fmt = self._fmt
    else:
        self._original_fmt = self._style._fmt
    self._level_to_fmt_mapping = {}

    levelname_fmt_match = self.LEVELNAME_FMT_REGEX.search(self._fmt)
    if not levelname_fmt_match:
        return
    levelname_fmt = levelname_fmt_match.group()

    for level, color_opts in self.LOGLEVEL_COLOROPTS.items():
        formatted_levelname = levelname_fmt % {
            "levelname": logging.getLevelName(level)
        }

        # add ANSI escape sequences around the formatted levelname
        color_kwargs = {name: True for name in color_opts}
        colorized_formatted_levelname = terminalwriter.markup(
            formatted_levelname, **color_kwargs
        )
        self._level_to_fmt_mapping[level] = self.LEVELNAME_FMT_REGEX.sub(
            colorized_formatted_levelname, self._fmt
        )

def format(self, record):
    fmt = self._level_to_fmt_mapping.get(record.levelno, self._original_fmt)
    if six.PY2:
        self._fmt = fmt
    else:
        self._style._fmt = fmt
    return super(ColoredLevelFormatter, self).format(record)

def getini(self, name):
    """ return configuration value from an :ref:`ini file <inifiles>`. If the
    specified name hasn't been registered through a prior
    :py:func:`parser.addini <_pytest.config.Parser.addini>`
    call (usually from a plugin), a ValueError is raised. """
    try:
        return self._inicache[name]
    except KeyError:
        self._inicache[name] = val = self._getini(name)
        return val

def _getini(self, name):
    try:
        description, type, default = self._parser._inidict[name]
    except KeyError:
        raise ValueError("unknown configuration value: %r" % (name,))
    value = self._get_override_ini_value(name)
    if value is None:
        try:
            value = self.inicfg[name]
        except KeyError:
            if default is not None:
                return default
            if type is None:
                return ""
            return []
    if type == "pathlist":
        dp = py.path.local(self.inicfg.config.path).dirpath()
        values = []
        for relpath in shlex.split(value):
            values.append(dp.join(relpath, abs=True))
        return values
    elif type == "args":
        return shlex.split(value)
    elif type == "linelist":
        return [t for t in map(lambda x: x.strip(), value.split("\n")) if t]
    elif type == "bool":
        return bool(_strtobool(value.strip()))
    else:
        assert type is None
        return value

def _get_override_ini_value(self, name):
    value = None
    # override_ini is a list of "ini=value" options
    # always use the last item if multiple values are set for same ini-name,
    # e.g. -o foo=bar1 -o foo=bar2 will set foo to bar2
    for ini_config in self._override_ini:
        try:
            key, user_ini_value = ini_config.split("=", 1)
        except ValueError:
            raise UsageError("-o/--override-ini expects option=value style.")
        else:
            if key == name:
                value = user_ini_value
    return value

def _processopt(self, opt):
    for name in opt._short_opts + opt._long_opts:
        self._opt2dest[name] = opt.dest

    if hasattr(opt, "default") and opt.dest:
        if not hasattr(self.option, opt.dest):
            setattr(self.option, opt.dest, opt.default)

def repr_excinfo(self, excinfo):

    repr_chain = []
    e = excinfo.value
    descr = None
    seen = set()
    while e is not None and id(e) not in seen:
        seen.add(id(e))
        if excinfo:
            reprtraceback = self.repr_traceback(excinfo)
            reprcrash = excinfo._getreprcrash()
        else:
            # fallback to native repr if the exception doesn't have a traceback:
            # ExceptionInfo objects require a full traceback to work
            reprtraceback = ReprTracebackNative(
                traceback.format_exception(type(e), e, None)
            )
            reprcrash = None

        repr_chain += [(reprtraceback, reprcrash, descr)]
        if e.__cause__ is not None and self.chain:
            e = e.__cause__
            excinfo = (
                ExceptionInfo((type(e), e, e.__traceback__))
                if e.__traceback__
                else None
            )
            descr = "The above exception was the direct cause of the following exception:"
        elif (
            e.__context__ is not None and not e.__suppress_context__ and self.chain
        ):
            e = e.__context__
            excinfo = (
                ExceptionInfo((type(e), e, e.__traceback__))
                if e.__traceback__
                else None
            )
            descr = "During handling of the above exception, another exception occurred:"
        else:
            e = None
    repr_chain.reverse()
    return ExceptionChainRepr(repr_chain)

def repr_traceback(self, excinfo):
    traceback = excinfo.traceback
    if self.tbfilter:
        traceback = traceback.filter()

    if excinfo.errisinstance(RecursionError):
        traceback, extraline = self._truncate_recursive_traceback(traceback)
    else:
        extraline = None

    last = traceback[-1]
    entries = []
    for index, entry in enumerate(traceback):
        einfo = (last == entry) and excinfo or None
        reprentry = self.repr_traceback_entry(entry, einfo)
        entries.append(reprentry)
    return ReprTraceback(entries, extraline, style=self.style)

def _getentrysource(self, entry):
    source = entry.getsource(self.astcache)
    if source is not None:
        source = source.deindent()
    return source

def __str__(self):
    try:
        fn = str(self.path)
    except py.error.Error:
        fn = "???"
    name = self.frame.code.name
    try:
        line = str(self.statement).lstrip()
    except KeyboardInterrupt:
        raise
    except:  # noqa
        line = "???"
    return "  File %r:%d in %s\n  %s\n" % (fn, self.lineno + 1, name, line)

def _getreprcrash(self):
    exconly = self.exconly(tryshort=True)
    entry = self.traceback.getcrashentry()
    path, lineno = entry.frame.code.raw.co_filename, entry.lineno
    return ReprFileLocation(path, lineno + 1, exconly)

def getcrashentry(self):
    """ return last non-hidden traceback entry that lead
    to the exception of a traceback.
    """
    for i in range(-1, -len(self) - 1, -1):
        entry = self[i]
        if not entry.ishidden():
            return entry
    return self[-1]

def _diff_text(left, right, verbose=0):
    """Return the explanation for the diff between text or bytes.

    Unless --verbose is used this will skip leading and trailing
    characters which are identical to keep the diff minimal.

    If the input are bytes they will be safely converted to text.
    """
    from difflib import ndiff

    explanation = []

    def escape_for_readable_diff(binary_text):
        """
        Ensures that the internal string is always valid unicode, converting any bytes safely to valid unicode.
        This is done using repr() which then needs post-processing to fix the encompassing quotes and un-escape
        newlines and carriage returns (#429).
        """
        r = str(repr(binary_text)[1:-1])
        r = r.replace(r"\n", "\n")
        r = r.replace(r"\r", "\r")
        return r

    if isinstance(left, bytes):
        left = escape_for_readable_diff(left)
    if isinstance(right, bytes):
        right = escape_for_readable_diff(right)
    if verbose < 1:
        i = 0  # just in case left or right has zero length
        for i in range(min(len(left), len(right))):
            if left[i] != right[i]:
                break
        if i > 42:
            i -= 10  # Provide some context
            explanation = [
                "Skipping %s identical leading characters in diff, use -v to show" % i
            ]
            left = left[i:]
            right = right[i:]
        if len(left) == len(right):
            for i in range(len(left)):
                if left[-i] != right[-i]:
                    break
            if i > 42:
                i -= 10  # Provide some context
                explanation += [
                    "Skipping {} identical trailing "
                    "characters in diff, use -v to show".format(i)
                ]
                left = left[:-i]
                right = right[:-i]
    keepends = True
    if left.isspace() or right.isspace():
        left = repr(str(left))
        right = repr(str(right))
        explanation += ["Strings contain only whitespace, escaping them using repr()"]
    explanation += [
        line.strip("\n")
        for line in ndiff(left.splitlines(keepends), right.splitlines(keepends))
    ]
    return explanation

def _compare_eq_sequence(left, right, verbose=0):
    explanation = []
    len_left = len(left)
    len_right = len(right)
    for i in range(min(len_left, len_right)):
        if left[i] != right[i]:
            explanation += [
                "At index {} diff: {!r} != {!r}".format(i, left[i], right[i])
            ]
            break
    len_diff = len_left - len_right

    if len_diff:
        if len_diff > 0:
            dir_with_more = "Left"
            extra = saferepr(left[len_right])
        else:
            len_diff = 0 - len_diff
            dir_with_more = "Right"
            extra = saferepr(right[len_left])

        if len_diff == 1:
            explanation += [
                "{} contains one more item: {}".format(dir_with_more, extra)
            ]
        else:
            explanation += [
                "%s contains %d more items, first extra item: %s"
                % (dir_with_more, len_diff, extra)
            ]
    return explanation

def _compare_eq_set(left, right, verbose=0):
    explanation = []
    diff_left = left - right
    diff_right = right - left
    if diff_left:
        explanation.append("Extra items in the left set:")
        for item in diff_left:
            explanation.append(saferepr(item))
    if diff_right:
        explanation.append("Extra items in the right set:")
        for item in diff_right:
            explanation.append(saferepr(item))
    return explanation

def _compare_eq_dict(left, right, verbose=0):
    explanation = []
    set_left = set(left)
    set_right = set(right)
    common = set_left.intersection(set_right)
    same = {k: left[k] for k in common if left[k] == right[k]}
    if same and verbose < 2:
        explanation += ["Omitting %s identical items, use -vv to show" % len(same)]
    elif same:
        explanation += ["Common items:"]
        explanation += pprint.pformat(same).splitlines()
    diff = {k for k in common if left[k] != right[k]}
    if diff:
        explanation += ["Differing items:"]
        for k in diff:
            explanation += [saferepr({k: left[k]}) + " != " + saferepr({k: right[k]})]
    extra_left = set_left - set_right
    len_extra_left = len(extra_left)
    if len_extra_left:
        explanation.append(
            "Left contains %d more item%s:"
            % (len_extra_left, "" if len_extra_left == 1 else "s")
        )
        explanation.extend(
            pprint.pformat({k: left[k] for k in extra_left}).splitlines()
        )
    extra_right = set_right - set_left
    len_extra_right = len(extra_right)
    if len_extra_right:
        explanation.append(
            "Right contains %d more item%s:"
            % (len_extra_right, "" if len_extra_right == 1 else "s")
        )
        explanation.extend(
            pprint.pformat({k: right[k] for k in extra_right}).splitlines()
        )
    return explanation

def _compare_eq_cls(left, right, verbose, type_fns):
    isdatacls, isattrs = type_fns
    if isdatacls(left):
        all_fields = left.__dataclass_fields__
        fields_to_check = [field for field, info in all_fields.items() if info.compare]
    elif isattrs(left):
        all_fields = left.__attrs_attrs__
        fields_to_check = [field.name for field in all_fields if field.cmp]

    same = []
    diff = []
    for field in fields_to_check:
        if getattr(left, field) == getattr(right, field):
            same.append(field)
        else:
            diff.append(field)

    explanation = []
    if same and verbose < 2:
        explanation.append("Omitting %s identical items, use -vv to show" % len(same))
    elif same:
        explanation += ["Matching attributes:"]
        explanation += pprint.pformat(same).splitlines()
    if diff:
        explanation += ["Differing attributes:"]
        for field in diff:
            explanation += [
                ("%s: %r != %r") % (field, getattr(left, field), getattr(right, field))
            ]
    return explanation

def to_xml(self):
    testcase = Junit.testcase(time="%.3f" % self.duration, **self.attrs)
    testcase.append(self.make_properties_node())
    for node in self.nodes:
        testcase.append(node)
    return testcase

def _get_global_properties_node(self):
    """Return a Junit node containing custom properties, if any.
    """
    if self.global_properties:
        return Junit.properties(
            [
                Junit.property(name=name, value=value)
                for name, value in self.global_properties
            ]
        )
    return ""

def parse(self, args, namespace=None):
    from _pytest._argcomplete import try_argcomplete

    self.optparser = self._getparser()
    try_argcomplete(self.optparser)
    args = [str(x) if isinstance(x, py.path.local) else x for x in args]
    return self.optparser.parse_args(args, namespace=namespace)

def pytest_cmdline_parse(self, pluginmanager, args):
    try:
        self.parse(args)
    except UsageError:

        # Handle --version and --help here in a minimal fashion.
        # This gets done via helpconfig normally, but its
        # pytest_cmdline_main is not called in case of errors.
        if getattr(self.option, "version", False) or "--version" in args:
            from _pytest.helpconfig import showversion

            showversion(self)
        elif (
            getattr(self.option, "help", False) or "--help" in args or "-h" in args
        ):
            self._parser._getparser().print_help()
            sys.stdout.write(
                "\nNOTE: displaying only minimal help due to UsageError.\n\n"
            )

        raise

    return self

def parse(self, args, addopts=True):
    # parse given cmdline arguments into this config object.
    assert not hasattr(
        self, "args"
    ), "can only parse cmdline args at most once per Config object"
    self.hook.pytest_addhooks.call_historic(
        kwargs=dict(pluginmanager=self.pluginmanager)
    )
    self._preparse(args, addopts=addopts)
    # XXX deprecated hook:
    self.hook.pytest_cmdline_preparse(config=self, args=args)
    self._parser.after_preparse = True
    try:
        args = self._parser.parse_setoption(
            args, self.option, namespace=self.option
        )
        if not args:
            if self.invocation_dir == self.rootdir:
                args = self.getini("testpaths")
            if not args:
                args = [str(self.invocation_dir)]
        self.args = args
    except PrintHelp:
        pass

def __init__(self, *names, **attrs):
    """store parms in private vars for use in add_argument"""
    self._attrs = attrs
    self._short_opts = []  # type: List[str]
    self._long_opts = []  # type: List[str]
    self.dest = attrs.get("dest")
    if "%default" in (attrs.get("help") or ""):
        warnings.warn(
            'pytest now uses argparse. "%default" should be'
            ' changed to "%(default)s" ',
            DeprecationWarning,
            stacklevel=3,
        )
    try:
        typ = attrs["type"]
    except KeyError:
        pass
    else:
        # this might raise a keyerror as well, don't want to catch that
        if isinstance(typ, str):
            if typ == "choice":
                warnings.warn(
                    "`type` argument to addoption() is the string %r."
                    " For choices this is optional and can be omitted, "
                    " but when supplied should be a type (for example `str` or `int`)."
                    " (options: %s)" % (typ, names),
                    DeprecationWarning,
                    stacklevel=4,
                )
                # argparse expects a type here take it from
                # the type of the first element
                attrs["type"] = type(attrs["choices"][0])
            else:
                warnings.warn(
                    "`type` argument to addoption() is the string %r, "
                    " but when supplied should be a type (for example `str` or `int`)."
                    " (options: %s)" % (typ, names),
                    DeprecationWarning,
                    stacklevel=4,
                )
                attrs["type"] = Argument._typ_map[typ]
            # used in test_parseopt -> test_parse_defaultgetter
            self.type = attrs["type"]
        else:
            self.type = typ
    try:
        # attribute existence is tested in Config._processopt
        self.default = attrs["default"]
    except KeyError:
        pass
    self._set_opt_strings(names)
    if not self.dest:
        if self._long_opts:
            self.dest = self._long_opts[0][2:].replace("-", "_")
        else:
            try:
                self.dest = self._short_opts[0][1:]
            except IndexError:
                raise ArgumentError("need a long or short option", self)

def _set_opt_strings(self, opts):
    """directly from optparse

    might not be necessary as this is passed to argparse later on"""
    for opt in opts:
        if len(opt) < 2:
            raise ArgumentError(
                "invalid option string %r: "
                "must be at least two characters long" % opt,
                self,
            )
        elif len(opt) == 2:
            if not (opt[0] == "-" and opt[1] != "-"):
                raise ArgumentError(
                    "invalid short option string %r: "
                    "must be of the form -x, (x any non-dash char)" % opt,
                    self,
                )
            self._short_opts.append(opt)
        else:
            if not (opt[0:2] == "--" and opt[2] != "-"):
                raise ArgumentError(
                    "invalid long option string %r: "
                    "must start with --, followed by non-dash" % opt,
                    self,
                )
            self._long_opts.append(opt)

def repr(self, x: Any) -> str:
    try:
        s = super().repr(x)
    except (KeyboardInterrupt, SystemExit):
        raise
    except BaseException as exc:
        s = _format_repr_exception(exc, x)
    return _ellipsize(s, self.maxsize)

def _format_repr_exception(exc: BaseException, obj: Any) -> str:
    try:
        exc_info = _try_repr_or_str(exc)
    except (KeyboardInterrupt, SystemExit):
        raise
    except BaseException as exc:
        exc_info = "unpresentable exception ({})".format(_try_repr_or_str(exc))
    return "<[{} raised in repr()] {} object at 0x{:x}>".format(
        exc_info, obj.__class__.__name__, id(obj)
    )

def _try_repr_or_str(obj):
    try:
        return repr(obj)
    except (KeyboardInterrupt, SystemExit):
        raise
    except BaseException:
        return '{}("{}")'.format(type(obj).__name__, obj)

def repr_excinfo(self, excinfo: ExceptionInfo) -> "ExceptionChainRepr":
    repr_chain = (
        []
    )  # type: List[Tuple[ReprTraceback, Optional[ReprFileLocation], Optional[str]]]
    e = excinfo.value
    excinfo_ = excinfo  # type: Optional[ExceptionInfo]
    descr = None
    seen = set()  # type: Set[int]
    while e is not None and id(e) not in seen:
        seen.add(id(e))
        if excinfo_:
            reprtraceback = self.repr_traceback(excinfo_)
            reprcrash = excinfo_._getreprcrash()  # type: Optional[ReprFileLocation]
        else:
            # fallback to native repr if the exception doesn't have a traceback:
            # ExceptionInfo objects require a full traceback to work
            reprtraceback = ReprTracebackNative(
                traceback.format_exception(type(e), e, None)
            )
            reprcrash = None

        repr_chain += [(reprtraceback, reprcrash, descr)]
        if e.__cause__ is not None and self.chain:
            e = e.__cause__
            excinfo_ = (
                ExceptionInfo((type(e), e, e.__traceback__))
                if e.__traceback__
                else None
            )
            descr = "The above exception was the direct cause of the following exception:"
        elif (
            e.__context__ is not None and not e.__suppress_context__ and self.chain
        ):
            e = e.__context__
            excinfo_ = (
                ExceptionInfo((type(e), e, e.__traceback__))
                if e.__traceback__
                else None
            )
            descr = "During handling of the above exception, another exception occurred:"
        else:
            e = None
    repr_chain.reverse()
    return ExceptionChainRepr(repr_chain)

def repr_traceback(self, excinfo: ExceptionInfo) -> "ReprTraceback":
    traceback = excinfo.traceback
    if self.tbfilter:
        traceback = traceback.filter()

    if excinfo.errisinstance(RecursionError):
        traceback, extraline = self._truncate_recursive_traceback(traceback)
    else:
        extraline = None

    last = traceback[-1]
    entries = []
    for index, entry in enumerate(traceback):
        einfo = (last == entry) and excinfo or None
        reprentry = self.repr_traceback_entry(entry, einfo)
        entries.append(reprentry)
    return ReprTraceback(entries, extraline, style=self.style)

def repr_traceback_entry(
    self, entry: TracebackEntry, excinfo: Optional[ExceptionInfo] = None
) -> "ReprEntry":
    import _pytest._code

    source = self._getentrysource(entry)
    if source is None:
        source = _pytest._code.Source("???")
        line_index = 0
    else:
        line_index = entry.lineno - entry.getfirstlinesource()

    lines = []  # type: List[str]
    style = entry._repr_style if entry._repr_style is not None else self.style
    if style in ("short", "long"):
        short = style == "short"
        reprargs = self.repr_args(entry) if not short else None
        s = self.get_source(source, line_index, excinfo, short=short)
        lines.extend(s)
        if short:
            message = "in %s" % (entry.name)
        else:
            message = excinfo and excinfo.typename or ""
        path = self._makepath(entry.path)
        reprfileloc = ReprFileLocation(path, entry.lineno + 1, message)
        localsrepr = self.repr_locals(entry.locals)
        return ReprEntry(lines, reprargs, localsrepr, reprfileloc, style)
    if excinfo:
        lines.extend(self.get_exconly(excinfo, indent=4))
    return ReprEntry(lines, None, None, None, style)

def _check_initialpaths_for_relpath(session, fspath):
    for initial_path in session._initialpaths:
        if fspath.common(initial_path) == initial_path:
            return fspath.relto(initial_path)

def _node_location_to_relpath(self, node_path: py.path.local) -> str:
    # bestrelpath is a quite slow function
    return self._bestrelpathcache[node_path]

def resolve_from_str(input, root):
    assert not isinstance(input, Path), "would break on py2"
    root = Path(root)
    input = expanduser(input)
    input = expandvars(input)
    if isabs(input):
        return Path(input)
    else:
        return root.joinpath(input)

def get_fslocation_from_item(
    item: "Item",
) -> Tuple[Union[str, py.path.local], Optional[int]]:
    """Tries to extract the actual location from an item, depending on available attributes:

    * "fslocation": a pair (path, lineno)
    * "obj": a Python object that the item wraps.
    * "fspath": just a path

    :rtype: a tuple of (str|LocalPath, int) with filename and line number.
    """
    try:
        return item.location[:2]
    except AttributeError:
        pass
    obj = getattr(item, "obj", None)
    if obj is not None:
        return getfslineno(obj)
    return getattr(item, "fspath", "unknown location"), -1

def location(self) -> Tuple[str, Optional[int], str]:
    location = self.reportinfo()
    if isinstance(location[0], py.path.local):
        fspath = location[0]
    else:
        fspath = py.path.local(location[0])
    relfspath = self.session._node_location_to_relpath(fspath)
    assert type(location[2]) is str
    return (relfspath, location[1], location[2])

def _getglobals(self) -> Dict[str, object]:
    d = {"os": os, "sys": sys, "platform": platform, "config": self.item.config}
    if hasattr(self.item, "obj"):
        d.update(self.item.obj.__globals__)  # type: ignore[attr-defined] # noqa: F821
    return d

def cached_eval(config: Config, expr: str, d: Dict[str, object]) -> Any:
    default = {}  # type: Dict[str, object]
    evalcache = config._store.setdefault(evalcache_key, default)
    try:
        return evalcache[expr]
    except KeyError:
        import _pytest._code

        exprcode = _pytest._code.compile(expr, mode="eval")
        evalcache[expr] = x = eval(exprcode, d)
        return x

def _istrue(self) -> bool:
    if hasattr(self, "result"):
        result = getattr(self, "result")  # type: bool
        return result
    self._marks = self._get_marks()

    if self._marks:
        self.result = False
        for mark in self._marks:
            self._mark = mark
            if "condition" not in mark.kwargs:
                args = mark.args
            else:
                args = (mark.kwargs["condition"],)

            for expr in args:
                self.expr = expr
                if isinstance(expr, str):
                    d = self._getglobals()
                    result = cached_eval(self.item.config, expr, d)
                else:
                    if "reason" not in mark.kwargs:
                        # XXX better be checked at collection time
                        msg = (
                            "you need to specify reason=STRING "
                            "when using booleans as conditions."
                        )
                        fail(msg)
                    result = bool(expr)
                if result:
                    self.result = True
                    self.reason = mark.kwargs.get("reason", None)
                    self.expr = expr
                    return self.result

            if not args:
                self.result = True
                self.reason = mark.kwargs.get("reason", None)
                return self.result
    return False

def pytest_runtest_setup(item: Item) -> None:
    # Check if skip or skipif are specified as pytest marks
    item._store[skipped_by_mark_key] = False
    eval_skipif = MarkEvaluator(item, "skipif")
    if eval_skipif.istrue():
        item._store[skipped_by_mark_key] = True
        skip(eval_skipif.getexplanation())

    for skip_info in item.iter_markers(name="skip"):
        item._store[skipped_by_mark_key] = True
        if "reason" in skip_info.kwargs:
            skip(skip_info.kwargs["reason"])
        elif skip_info.args:
            skip(skip_info.args[0])
        else:
            skip("unconditional skip")

    item._store[evalxfail_key] = MarkEvaluator(item, "xfail")
    check_xfail_no_run(item)

def getexplanation(self):
    expl = getattr(self, "reason", None) or self.get("reason", None)
    if not expl:
        if not hasattr(self, "expr"):
            return ""
        else:
            return "condition: " + str(self.expr)
    return expl

def check_xfail_no_run(item: Item) -> None:
    """check xfail(run=False)"""
    if not item.config.option.runxfail:
        evalxfail = item._store[evalxfail_key]
        if evalxfail.istrue():
            if not evalxfail.get("run", True):
                xfail("[NOTRUN] " + evalxfail.getexplanation())

def invalidraise(self, exc) -> Optional[bool]:
    raises = self.get("raises")
    if not raises:
        return None
    return not isinstance(exc, raises)

def __bool__(self) -> bool:
    # don't cache here to prevent staleness
    return bool(self._get_marks())

def location(self) -> Tuple[str, Optional[int], str]:
    location = self.reportinfo()
    if isinstance(location[0], py.path.local):
        fspath = location[0]
    else:
        fspath = py.path.local(location[0])
    relfspath = self.session._node_location_to_relpath(fspath)
    assert type(location[2]) is str
    return (relfspath, location[1], location[2])

def evaluate_skip_marks(item: Item) -> Optional[Skip]:
    """Evaluate skip and skipif marks on item, returning Skip if triggered."""
    for mark in item.iter_markers(name="skipif"):
        if "condition" not in mark.kwargs:
            conditions = mark.args
        else:
            conditions = (mark.kwargs["condition"],)

        # Unconditional.
        if not conditions:
            reason = mark.kwargs.get("reason", "")
            return Skip(reason)

        # If any of the conditions are true.
        for condition in conditions:
            result, reason = evaluate_condition(item, mark, condition)
            if result:
                return Skip(reason)

    for mark in item.iter_markers(name="skip"):
        if "reason" in mark.kwargs:
            reason = mark.kwargs["reason"]
        elif mark.args:
            reason = mark.args[0]
        else:
            reason = "unconditional skip"
        return Skip(reason)

    return None

def pytest_runtest_setup(item: Item) -> None:
    item._store[skipped_by_mark_key] = False

    skipped = evaluate_skip_marks(item)
    if skipped:
        item._store[skipped_by_mark_key] = True
        skip(skipped.reason)

    if not item.config.option.runxfail:
        item._store[xfailed_key] = xfailed = evaluate_xfail_marks(item)
        if xfailed and not xfailed.run:
            xfail("[NOTRUN] " + xfailed.reason)

def evaluate_xfail_marks(item: Item) -> Optional[Xfail]:
    """Evaluate xfail marks on item, returning Xfail if triggered."""
    for mark in item.iter_markers(name="xfail"):
        run = mark.kwargs.get("run", True)
        strict = mark.kwargs.get("strict", item.config.getini("xfail_strict"))
        raises = mark.kwargs.get("raises", None)
        if "condition" not in mark.kwargs:
            conditions = mark.args
        else:
            conditions = (mark.kwargs["condition"],)

        # Unconditional.
        if not conditions:
            reason = mark.kwargs.get("reason", "")
            return Xfail(reason, run, strict, raises)

        # If any of the conditions are true.
        for condition in conditions:
            result, reason = evaluate_condition(item, mark, condition)
            if result:
                return Xfail(reason, run, strict, raises)

    return None

def evaluate_condition(item: Item, mark: Mark, condition: object) -> Tuple[bool, str]:
    """Evaluate a single skipif/xfail condition.

    If an old-style string condition is given, it is eval()'d, otherwise the
    condition is bool()'d. If this fails, an appropriately formatted pytest.fail
    is raised.

    Returns (result, reason). The reason is only relevant if the result is True.
    """
    # String condition.
    if isinstance(condition, str):
        globals_ = {
            "os": os,
            "sys": sys,
            "platform": platform,
            "config": item.config,
        }
        if hasattr(item, "obj"):
            globals_.update(item.obj.__globals__)  # type: ignore[attr-defined]
        try:
            filename = "<{} condition>".format(mark.name)
            condition_code = compile(condition, filename, "eval")
            result = eval(condition_code, globals_)
        except SyntaxError as exc:
            msglines = [
                "Error evaluating %r condition" % mark.name,
                "    " + condition,
                "    " + " " * (exc.offset or 0) + "^",
                "SyntaxError: invalid syntax",
            ]
            fail("\n".join(msglines), pytrace=False)
        except Exception as exc:
            msglines = [
                "Error evaluating %r condition" % mark.name,
                "    " + condition,
                *traceback.format_exception_only(type(exc), exc),
            ]
            fail("\n".join(msglines), pytrace=False)

    # Boolean condition.
    else:
        try:
            result = bool(condition)
        except Exception as exc:
            msglines = [
                "Error evaluating %r condition as a boolean" % mark.name,
                *traceback.format_exception_only(type(exc), exc),
            ]
            fail("\n".join(msglines), pytrace=False)

    reason = mark.kwargs.get("reason", None)
    if reason is None:
        if isinstance(condition, str):
            reason = "condition: " + condition
        else:
            # XXX better be checked at collection time
            msg = (
                "Error evaluating %r: " % mark.name
                + "you need to specify reason=STRING when using booleans as conditions."
            )
            fail(msg, pytrace=False)

    return result, reason

def add_marker(
    self, marker: Union[str, MarkDecorator], append: bool = True
) -> None:
    """dynamically add a marker object to the node.

    :type marker: ``str`` or ``pytest.mark.*``  object
    :param marker:
        ``append=True`` whether to append the marker,
        if ``False`` insert at position ``0``.
    """
    from _pytest.mark import MARK_GEN

    if isinstance(marker, MarkDecorator):
        marker_ = marker
    elif isinstance(marker, str):
        marker_ = getattr(MARK_GEN, marker)
    else:
        raise ValueError("is not a string or pytest.mark.* Marker")
    self.keywords[marker_.name] = marker_
    if append:
        self.own_markers.append(marker_.mark)
    else:
        self.own_markers.insert(0, marker_.mark)

def iter_markers(self, name: Optional[str] = None) -> Iterator[Mark]:
    """
    :param name: if given, filter the results by the name attribute

    iterate over all markers of the node
    """
    return (x[1] for x in self.iter_markers_with_node(name=name))

def getbasetemp(self) -> py.path.local:
    """Backward compat wrapper for ``_tmppath_factory.getbasetemp``."""
    return py.path.local(self._tmppath_factory.getbasetemp().resolve())

def get_user() -> Optional[str]:
    """Return the current user name, or None if getuser() does not work
    in the current environment (see #1010)."""
    import getpass

    try:
        return getpass.getuser()
    except (ImportError, KeyError):
        return None

def _mk_tmp(request: FixtureRequest, factory: TempPathFactory) -> Path:
    name = request.node.name
    name = re.sub(r"[\W]", "_", name)
    MAXVAL = 30
    name = name[:MAXVAL]
    return factory.mktemp(name, numbered=True)

def make_numbered_dir(root: Path, prefix: str) -> Path:
    """Create a directory with an increased number as suffix for the given prefix."""
    for i in range(10):
        # try up to 10 times to create the folder
        max_existing = max(map(parse_num, find_suffixes(root, prefix)), default=-1)
        new_number = max_existing + 1
        new_path = root.joinpath(f"{prefix}{new_number}")
        try:
            new_path.mkdir()
        except Exception:
            pass
        else:
            _force_symlink(root, prefix + "current", new_path)
            return new_path
    else:
        raise OSError(
            "could not create numbered dir with prefix "
            "{prefix} in {root} after 10 tries".format(prefix=prefix, root=root)
        )

def ensure_deletable(path: Path, consider_lock_dead_if_created_before: float) -> bool:
    """Check if `path` is deletable based on whether the lock file is expired."""
    if path.is_symlink():
        return False
    lock = get_lock_path(path)
    try:
        if not lock.is_file():
            return True
    except OSError:
        # we might not have access to the lock file at all, in this case assume
        # we don't have access to the entire directory (#7491).
        return False
    try:
        lock_time = lock.stat().st_mtime
    except Exception:
        return False
    else:
        if lock_time < consider_lock_dead_if_created_before:
            # We want to ignore any errors while trying to remove the lock such as:
            # - PermissionDenied, like the file permissions have changed since the lock creation;
            # - FileNotFoundError, in case another pytest process got here first;
            # and any other cause of failure.
            with contextlib.suppress(OSError):
                lock.unlink()
                return True
        return False

def validate_basetemp(path: str) -> str:
    # GH 7119
    msg = "basetemp must not be empty, the current working directory or any parent directory of it"

    # empty path
    if not path:
        raise argparse.ArgumentTypeError(msg)

    def is_ancestor(base: Path, query: Path) -> bool:
        """Return whether query is an ancestor of base."""
        if base == query:
            return True
        for parent in base.parents:
            if parent == query:
                return True
        return False

    # check if path is an ancestor of cwd
    if is_ancestor(Path.cwd(), Path(path).absolute()):
        raise argparse.ArgumentTypeError(msg)

    # check symlinks for ancestors
    if is_ancestor(Path.cwd().resolve(), Path(path).resolve()):
        raise argparse.ArgumentTypeError(msg)

    return path

def locate_config(
    args: Iterable[Path],
) -> Tuple[Optional[Path], Optional[Path], Dict[str, Union[str, List[str]]]]:
    """Search in the list of arguments for a valid ini-file for pytest,
    and return a tuple of (rootdir, inifile, cfg-dict)."""
    config_names = [
        "pytest.ini",
        "pyproject.toml",
        "tox.ini",
        "setup.cfg",
    ]
    args = [x for x in args if not str(x).startswith("-")]
    if not args:
        args = [Path.cwd()]
    for arg in args:
        argpath = absolutepath(arg)
        for base in (argpath, *argpath.parents):
            for config_name in config_names:
                p = base / config_name
                if p.is_file():
                    ini_config = load_config_dict_from_file(p)
                    if ini_config is not None:
                        return base, p, ini_config
    return None, None, {}

def _ensure_relative_to_basetemp(self, basename: str) -> str:
    basename = os.path.normpath(basename)
    if (self.getbasetemp() / basename).resolve().parent != self.getbasetemp():
        raise ValueError(f"{basename} is not a normalized and relative path")
    return basename

def mktemp(self, basename: str, numbered: bool = True) -> py.path.local:
    """Same as :meth:`TempPathFactory.mktemp`, but returns a ``py.path.local`` object."""
    return py.path.local(self._tmppath_factory.mktemp(basename, numbered).resolve())

def evaluate_condition(item: Item, mark: Mark, condition: object) -> Tuple[bool, str]:
    """Evaluate a single skipif/xfail condition.

    If an old-style string condition is given, it is eval()'d, otherwise the
    condition is bool()'d. If this fails, an appropriately formatted pytest.fail
    is raised.

    Returns (result, reason). The reason is only relevant if the result is True.
    """
    # String condition.
    if isinstance(condition, str):
        globals_ = {
            "os": os,
            "sys": sys,
            "platform": platform,
            "config": item.config,
        }
        for dictionary in reversed(
            item.ihook.pytest_markeval_namespace(config=item.config)
        ):
            if not isinstance(dictionary, Mapping):
                raise ValueError(
                    "pytest_markeval_namespace() needs to return a dict, got {!r}".format(
                        dictionary
                    )
                )
            globals_.update(dictionary)
        if hasattr(item, "obj"):
            globals_.update(item.obj.__globals__)  # type: ignore[attr-defined]
        try:
            filename = f"<{mark.name} condition>"
            condition_code = compile(condition, filename, "eval")
            result = eval(condition_code, globals_)
        except SyntaxError as exc:
            msglines = [
                "Error evaluating %r condition" % mark.name,
                "    " + condition,
                "    " + " " * (exc.offset or 0) + "^",
                "SyntaxError: invalid syntax",
            ]
            fail("\n".join(msglines), pytrace=False)
        except Exception as exc:
            msglines = [
                "Error evaluating %r condition" % mark.name,
                "    " + condition,
                *traceback.format_exception_only(type(exc), exc),
            ]
            fail("\n".join(msglines), pytrace=False)

    # Boolean condition.
    else:
        try:
            result = bool(condition)
        except Exception as exc:
            msglines = [
                "Error evaluating %r condition as a boolean" % mark.name,
                *traceback.format_exception_only(type(exc), exc),
            ]
            fail("\n".join(msglines), pytrace=False)

    reason = mark.kwargs.get("reason", None)
    if reason is None:
        if isinstance(condition, str):
            reason = "condition: " + condition
        else:
            # XXX better be checked at collection time
            msg = (
                "Error evaluating %r: " % mark.name
                + "you need to specify reason=STRING when using booleans as conditions."
            )
            fail(msg, pytrace=False)

    return result, reason

def pytest_pyfunc_call(pyfuncitem: "Function") -> Optional[object]:
    testfunction = pyfuncitem.obj
    if is_async_function(testfunction):
        async_warn_and_skip(pyfuncitem.nodeid)
    funcargs = pyfuncitem.funcargs
    testargs = {arg: funcargs[arg] for arg in pyfuncitem._fixtureinfo.argnames}
    result = testfunction(**testargs)
    if hasattr(result, "__await__") or hasattr(result, "__aiter__"):
        async_warn_and_skip(pyfuncitem.nodeid)
    return True

def pytest_collect_file(fspath: Path, parent: nodes.Collector) -> Optional["Module"]:
    if fspath.suffix == ".py":
        if not parent.session.isinitpath(fspath):
            if not path_matches_patterns(
                fspath, parent.config.getini("python_files") + ["__init__.py"]
            ):
                return None
        ihook = parent.session.gethookproxy(fspath)
        module: Module = ihook.pytest_pycollect_makemodule(fspath=fspath, parent=parent)
        return module
    return None

